    },
    {
      "label": "literature_gap_analyst",
      "instructions": "Search for academic literature connecting Quantum Darwinism and Holographic Quantum Error Correction. Specifically, identify if there is a known 'citation gap' or a missing link in the formal proof that connects the emergence of classicality via environmental redundancy to the protection of bulk information in AdS/CFT-based error correcting codes."
    }
  ],
  "synthesis_brief": "Combine the three identified mathematical correspondences with the findings regarding the existence or absence of a formal citation gap to determine if a formal relationship is established or merely conjectured."
}

